/*
 * Minimal offline Markdown renderer exposing a `marked.parse(md)` API
 * compatible subset of github.com/markedjs/marked for this site's needs:
 * headings, bold/italic, tables, unordered lists, paragraphs, line breaks.
 * Vendored (no CDN dependency) — intentionally small, not a full CommonMark impl.
 */
(function (global) {
  function escapeHtml(s) {
    return s
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;');
  }

  function inline(text) {
    let t = escapeHtml(text);
    t = t.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    t = t.replace(/(^|[^*])\*([^*]+)\*(?!\*)/g, '$1<em>$2</em>');
    return t;
  }

  function isTableSeparator(line) {
    return /^\|?\s*:?-+:?\s*(\|\s*:?-+:?\s*)*\|?$/.test(line.trim());
  }

  function splitRow(line) {
    let l = line.trim();
    if (l.startsWith('|')) l = l.slice(1);
    if (l.endsWith('|')) l = l.slice(0, -1);
    return l.split('|').map((c) => c.trim());
  }

  function renderTable(lines, startIdx) {
    const header = splitRow(lines[startIdx]);
    const aligns = splitRow(lines[startIdx + 1]).map((s) => {
      const l = s.startsWith(':'), r = s.endsWith(':');
      return l && r ? 'center' : r ? 'right' : '';
    });
    const attr = (idx) => (aligns[idx] ? ` align="${aligns[idx]}"` : '');
    let html = '<table><thead><tr>';
    header.forEach((h, idx) => { html += `<th${attr(idx)}>${inline(h)}</th>`; });
    html += '</tr></thead><tbody>';
    let i = startIdx + 2;
    for (; i < lines.length; i++) {
      const line = lines[i];
      if (!line.trim().startsWith('|') && line.trim() !== '') break;
      if (line.trim() === '') break;
      const cells = splitRow(line);
      html += '<tr>';
      cells.forEach((c, idx) => { html += `<td${attr(idx)}>${inline(c)}</td>`; });
      html += '</tr>';
    }
    html += '</tbody></table>';
    return { html, next: i };
  }

  function parse(md) {
    if (typeof md !== 'string') return '';
    if (md.includes('<script')) {
      return `<pre>${escapeHtml(md)}</pre>`;
    }
    const lines = md.replace(/\r\n/g, '\n').split('\n');
    let html = '';
    let i = 0;
    let inList = false;
    let paraBuf = [];

    function flushPara() {
      if (paraBuf.length) {
        html += `<p>${paraBuf.map(inline).join('<br>')}</p>`;
        paraBuf = [];
      }
    }
    function closeList() {
      if (inList) { html += '</ul>'; inList = false; }
    }

    while (i < lines.length) {
      const line = lines[i];

      if (line.trim() === '') {
        flushPara();
        closeList();
        i++;
        continue;
      }

      const heading = line.match(/^(#{1,6})\s+(.*)$/);
      if (heading) {
        flushPara();
        closeList();
        const level = heading[1].length;
        html += `<h${level}>${inline(heading[2])}</h${level}>`;
        i++;
        continue;
      }

      if (line.trim() === '---') {
        flushPara();
        closeList();
        html += '<hr>';
        i++;
        continue;
      }

      if (line.trim().startsWith('|') && lines[i + 1] && isTableSeparator(lines[i + 1])) {
        flushPara();
        closeList();
        const { html: tableHtml, next } = renderTable(lines, i);
        html += tableHtml;
        i = next;
        continue;
      }

      const listItem = line.match(/^\s*[-*]\s+(.*)$/);
      if (listItem) {
        flushPara();
        if (!inList) { html += '<ul>'; inList = true; }
        html += `<li>${inline(listItem[1])}</li>`;
        i++;
        continue;
      }

      const quote = line.match(/^>\s?(.*)$/);
      if (quote) {
        flushPara();
        closeList();
        html += `<blockquote>${inline(quote[1])}</blockquote>`;
        i++;
        continue;
      }

      closeList();
      paraBuf.push(line.trim());
      i++;
    }
    flushPara();
    closeList();
    return html;
  }

  global.marked = { parse };
})(typeof window !== 'undefined' ? window : this);
